#include <bits/stdc++.h>
using namespace std;
int main() {
    int n;
    cin >> n;
    vector<int> tasks(n);
    for (int i = 0; i < n; i++) cin >> tasks[i];
    int cooldown;
    cin >> cooldown;
    unordered_map<int, int> task_counts;
    for (int task : tasks) task_counts[task]++;
    int max_count = 0;
    int max_task_types = 0;
    for (auto& pair : task_counts) {
        if (pair.second > max_count) {
            max_count = pair.second;
            max_task_types = 1;
        } else if (pair.second == max_count) {
            max_task_types++;
        }
    }
    int idle_time = max(0, cooldown - (max_task_types - 1));
    cout << max((long long)tasks.size(), (long long)max_count + idle_time * cooldown) << endl;
}
